#include<bits/stdc++.h>
using namespace std;
int n,dp[1001][1001],a;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=i;j++){
            cin>>a;
            dp[i][j]=a;
        }
    for(int i=2;i<=n;i++)
        for(int j=1;j<=i;j++)
            dp[i][j]+=max(dp[i-1][j],dp[i-1][j-1]);
    int ans=-1;
    for(int i=1;i<=n;i++)ans=max(ans,dp[n][i]);
    cout<<ans;
    return 0;
}
